import boto3

def send_message_to_sqs(user_data, queue_url):
    sqs = boto3.client('sqs')

    message_body = {
        'Email': user_data.get('email'),
        'Phone Number': user_data.get('phone_num'),
        'Address': user_data.get('address'),
    }

    response = sqs.send_message(
        QueueUrl=queue_url,
        MessageBody=str(message_body),
    )

    return response

user_data = {
    'email': 'user@example.com',
    'phone_num': '+1234567890',
    'address': '123 Main St, Anytown, USA',
}

queue_url = 'https://sqs.aws-region.amazonaws.com/123456789012/MyQueue'

response = send_message_to_sqs(user_data, queue_url)

print('Message ID:', response['MessageId'])
print('MD5 of Message Body:', response['MD5OfMessageBody'])